            if (json.status != "success" || !json.data?.result) return results
            json.data.result.each { r ->
                def labels = r.metric ?: [:]
                def keyParts = keys.collect { labels[it] ?: "" }
                if (keyParts.every { it }) results[keyParts.join(sep)] = r.value ? r.value[1] : null
            }
        } catch (Exception e) {}
        return results
    }

    private String executeHttpGet(String url) {
        try {
            def http = Class.forName("com.santaba.agent.groovyapi.http.HTTP").newInstance()
            http.open(url); http.setHeader("Authorization", "Bearer ${token}")
            def r = http.get(); http.close(); return r
        } catch (ClassNotFoundException e) {
            def c = new URL(url).openConnection() as HttpURLConnection
            c.setRequestMethod("GET"); c.setRequestProperty("Authorization", "Bearer ${token}")
            c.setConnectTimeout(30000); c.setReadTimeout(60000)
            if (ssl) { try {
                def sc = javax.net.ssl.SSLContext.getInstance("TLS")
                sc.init(null, [new javax.net.ssl.X509TrustManager() {
                    void checkClientTrusted(java.security.cert.X509Certificate[] x, String a) {}
                    void checkServerTrusted(java.security.cert.X509Certificate[] x, String a) {}
                    java.security.cert.X509Certificate[] getAcceptedIssuers() { null }
                }] as javax.net.ssl.TrustManager[], new java.security.SecureRandom())
                c.setSSLSocketFactory(sc.getSocketFactory()); c.setHostnameVerifier({ h, s -> true })
            } catch (Exception ex) {} }
            if (c.getResponseCode() != 200) throw new RuntimeException("HTTP ${c.getResponseCode()}")
            return c.getInputStream().text
        }
    }
}

try {
    def client = new ThanosClient(hostProps)
    def metrics = [
        "read_bytes": 'rate(kubevirt_vmi_storage_read_traffic_bytes_total[5m])',
        "write_bytes": 'rate(kubevirt_vmi_storage_write_traffic_bytes_total[5m])',
        "read_iops": 'rate(kubevirt_vmi_storage_iops_read_total[5m])',
        "write_iops": 'rate(kubevirt_vmi_storage_iops_write_total[5m])',
        "read_time_rate": 'rate(kubevirt_vmi_storage_read_times_seconds_total[5m])',
        "write_time_rate": 'rate(kubevirt_vmi_storage_write_times_seconds_total[5m])',
        "flush_requests": 'rate(kubevirt_vmi_storage_flush_requests_total[5m])',
        "flush_time_rate": 'rate(kubevirt_vmi_storage_flush_times_seconds_total[5m])'
    ]
    def allData = [:]
    metrics.each { dp, q -> client.queryGroupedByKey(q, ["namespace", "name", "drive"]).each { k, v -> if (!allData[k]) allData[k] = [:]; allData[k][dp] = v } }
    allData.each { wv, dps ->
        if (dps.read_bytes != null) println "${wv}.read_bytes=${dps.read_bytes}"
        if (dps.write_bytes != null) println "${wv}.write_bytes=${dps.write_bytes}"
        if (dps.read_iops != null) println "${wv}.read_iops=${dps.read_iops}"
        if (dps.write_iops != null) println "${wv}.write_iops=${dps.write_iops}"
        if (dps.read_time_rate != null && dps.read_iops != null) {
            def ri = dps.read_iops as Double
            if (ri > 0) println "${wv}.read_latency_ms=${(dps.read_time_rate as Double) / ri * 1000}"
        }
        if (dps.write_time_rate != null && dps.write_iops != null) {
            def wi = dps.write_iops as Double
            if (wi > 0) println "${wv}.write_latency_ms=${(dps.write_time_rate as Double) / wi * 1000}"
        }
        if (dps.flush_requests != null) println "${wv}.flush_requests=${dps.flush_requests}"
        if (dps.flush_time_rate != null && dps.flush_requests != null) {
            def fr = dps.flush_requests as Double
            if (fr > 0) println "${wv}.flush_latency_ms=${(dps.flush_time_rate as Double) / fr * 1000}"
        }
    }
    return 0
} catch (Exception e) {
    System.err.println "ERROR: ${e.message}"
    return 1
}
